import React, { useState, useEffect } from "react";
import API from "../api";

function Dashboard() {
    const [file, setFile] = useState(null);
    const [resumes, setResumes] = useState([]);
    const [result, setResult] = useState([]);

    const [searchSkill, setSearchSkill] = useState("");
    const [searchExp, setSearchExp] = useState("");

    const [loading, setLoading] = useState(false);
    const [error, setError] = useState("");
    const [message, setMessage] = useState("");

    const [editingResume, setEditingResume] = useState(null);
    const [editForm, setEditForm] = useState({
        name: "",
        email: "",
        skills: "",
        experience: 0
    });

    // ✅ Fetch resumes on load
    useEffect(() => {
        fetchResumes();
    }, []);

    const fetchResumes = async () => {
        try {
            const res = await API.get("/resumes");
            setResumes(res.data);
        } catch (err) {
            console.error(err);
            setError("Failed to fetch resumes");
        }
    };

    // ✅ Upload Resume
    const handleUpload = async () => {
        if (!file) return alert("Select file first");

        setLoading(true);
        setError("");
        setMessage("");

        try {
            const formData = new FormData();
            formData.append("file", file);
            formData.append("name", "Test User");
            formData.append("email", "test@gmail.com");
            formData.append("skills", "java spring boot");
            formData.append("experience", 2);

            await API.post("/resumes/upload", formData, {
                headers: { "Content-Type": "multipart/form-data" }
            });

            setMessage("Resume uploaded successfully!");
            fetchResumes();
        } catch (err) {
            console.error(err);
            setError("Upload failed");
        }

        setLoading(false);
    };

    // ✅ Delete Resume
    const handleDelete = async (id) => {
        if (!window.confirm("Are you sure?")) return;

        try {
            await API.delete(`/resumes/${id}`);
            setMessage("Deleted successfully");
            fetchResumes();
        } catch (err) {
            console.error(err);
            setError("Delete failed");
        }
    };

    // ✅ Download Resume
    const handleDownload = async (id) => {
        try {
            const res = await API.get(`/resumes/download/${id}`, {
                responseType: "blob"
            });

            const url = window.URL.createObjectURL(new Blob([res.data]));
            const link = document.createElement("a");
            link.href = url;
            link.setAttribute("download", "resume.pdf");
            document.body.appendChild(link);
            link.click();
        } catch (err) {
            console.error(err);
            setError("Download failed");
        }
    };

    // ✅ Start Edit
    const startEdit = (resume) => {
        setEditingResume(resume);
        setEditForm({
            name: resume.name,
            email: resume.email,
            skills: resume.skills,
            experience: resume.experience
        });
    };

    // ✅ Update Resume
    const handleUpdate = async () => {
        try {
            await API.put(`/resumes/${editingResume.id}`, editForm);

            setMessage("Updated successfully");
            setEditingResume(null);
            fetchResumes();
        } catch (err) {
            console.error(err);
            setError("Update failed");
        }
    };

    // ✅ Search Matches
    const handleSearch = async () => {
        setLoading(true);
        setError("");

        try {
            const res = await API.get(
                `/resumes/match?skill=${searchSkill}&experience=${searchExp}`
            );
            setResult(res.data);
        } catch (err) {
            console.error(err);
            setError("Search failed");
        }

        setLoading(false);
    };

    // ✅ Default Matches
    const getMatches = async () => {
        setLoading(true);
        setError("");

        try {
            const res = await API.get(
                `/resumes/match?skill=java&experience=1`
            );
            setResult(res.data);
        } catch (err) {
            console.error(err);
            setError("Match failed");
        }

        setLoading(false);
    };

    // ✅ Logout
    const handleLogout = () => {
        localStorage.removeItem("token");
        window.location.href = "/login";
    };

    return (
        <div style={{
            maxWidth: "1000px",
            margin: "auto",
            padding: "20px",
            fontFamily: "Arial"
        }}>
            <h2 style={{ textAlign: "center" }}>TalentMatch AI</h2>

            <button onClick={handleLogout}>Logout</button>

            {loading && <p>Loading...</p>}
            {error && <p style={{ color: "red" }}>{error}</p>}
            {message && <p style={{ color: "green" }}>{message}</p>}

            <hr />

            {/* ✅ EDIT FORM */}
            {editingResume && (
                <div style={{ border: "1px solid black", padding: 15 }}>
                    <h3>Edit Resume</h3>

                    <input
                        value={editForm.name}
                        onChange={(e) =>
                            setEditForm({ ...editForm, name: e.target.value })
                        }
                        placeholder="Name"
                    /><br /><br />

                    <input
                        value={editForm.email}
                        onChange={(e) =>
                            setEditForm({ ...editForm, email: e.target.value })
                        }
                        placeholder="Email"
                    /><br /><br />

                    <input
                        value={editForm.skills}
                        onChange={(e) =>
                            setEditForm({ ...editForm, skills: e.target.value })
                        }
                        placeholder="Skills"
                    /><br /><br />

                    <input
                        type="number"
                        value={editForm.experience}
                        onChange={(e) =>
                            setEditForm({ ...editForm, experience: e.target.value })
                        }
                    /><br /><br />

                    <button onClick={handleUpdate}>Update</button>
                    <button onClick={() => setEditingResume(null)}>Cancel</button>
                </div>
            )}

            <hr />

            {/* ✅ UPLOAD */}
            <h3>Add Resume</h3>
            <input type="file" onChange={(e) => setFile(e.target.files[0])} />
            <br /><br />
            <button onClick={handleUpload}>
                {loading ? "Uploading..." : "Upload"}
            </button>

            <hr />

            {/* ✅ SEARCH */}
            <h3>Search Resumes</h3>

            <input
                placeholder="Skill"
                value={searchSkill}
                onChange={(e) => setSearchSkill(e.target.value)}
            />

            <input
                type="number"
                placeholder="Experience"
                value={searchExp}
                onChange={(e) => setSearchExp(e.target.value)}
            />

            <button onClick={handleSearch}>Search</button>

            <hr />

            {/* ✅ RESUME LIST */}
            <h3>Your Resumes</h3>

            {resumes.length === 0 ? (
                <p>No resumes</p>
            ) : (
                <ul>
                    {resumes.map((r) => (
                        <li key={r.id}>
                            <b>{r.name}</b> - {r.skills} ({r.experience} yrs)
                            <br />
                            <button onClick={() => startEdit(r)}>Edit</button>
                            <button onClick={() => handleDownload(r.id)}>Download</button>
                            <button onClick={() => handleDelete(r.id)}>Delete</button>
                        </li>
                    ))}
                </ul>
            )}

            <hr />

            {/* ✅ MATCH RESULTS */}
            <h3>Find Matches</h3>
            <button onClick={getMatches}>Find Matches</button>

            {!loading && result.length === 0 && (
                <p style={{ color: "gray" }}>No matches found</p>
            )}

            <div style={{
                display: "grid",
                gridTemplateColumns: "repeat(3,1fr)",
                gap: "20px",
                marginTop: "20px"
            }}>
                {result.map((r, i) => (
                    <div key={i} style={{
                        border: "1px solid #ddd",
                        padding: "15px",
                        borderRadius: "10px"
                    }}>
                        <h3>{r?.summary?.name}</h3>
                        <p>Email: {r?.summary?.email}</p>
                        <p>Skills: {r?.summary?.skills}</p>
                        <p>Experience: {r?.summary?.experience}</p>
                        <p>Score: {r?.score}/100</p>

                        <div style={{ background: "#eee", height: "10px" }}>
                            <div style={{
                                width: `${r?.score}%`,
                                background: "green",
                                height: "10px"
                            }}></div>
                        </div>

                        <button onClick={() => handleDownload(r.summary.id)}>
                            Download
                        </button>
                    </div>
                ))}
            </div>
        </div>
    );
}

export default Dashboard;
